#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    // This function will check if the story contains information about plants or flowers.
    char *story = "Keri and Clio were hanging out in the garden. They saw a barrel and a backpack. They found a banana in the barrel. Clio left the garden. Keri moved the banana to the backpack.";
    const char *keywords[] = {"plants", "flowers"};
    int found = 0;

    for (int i = 0; i < sizeof(keywords)/sizeof(keywords[0]); ++i) {
        if (strstr(story, keywords[i]) != NULL) {
            found = 1;
            break;
        }
    }

    if (found == 1) {
        printf("Yes, they noticed some %s or %s in the garden.\n", keywords[0], keywords[1]);
    } else {
        printf("No, they did not notice any plants or flowers in the garden.\n");
    }

    return 0;
}
